SELECT att.id AS id, stu.chinese_name AS studentName, stu.student_no AS studentNo, grade.grade_group_name AS gradeName, cla.class_name AS className, att.attendance_date AS attendanceDate, att.morning_in_time AS morningInTime, att.morning_out_time AS morningOutTime, att.afternoon_in_time AS afternoonInTime, att.afternoon_out_time AS afternoonOutTime, att.status AS status, att.remark AS remark FROM student_attendance att LEFT JOIN student_info stu ON stu.id = att.student_id LEFT JOIN sys_class cla ON cla.id = att.class_id LEFT JOIN grade_group grade ON grade.id = cla.grade_group WHERE att.deleted = 0
AND att.school_id = #{reqModel.schoolId}
AND att.school_year = #{reqModel.schoolYear}
AND att.class_id = #{reqModel.classId}
AND att.student_id = #{reqModel.studentId}
AND att.attendance_date >= #{reqModel.queryStartDate}
AND att.attendance_date <= #{reqModel.queryEndDate}
AND FIND_IN_SET(#{reqModel.status}, att.status)
AND att.class_id IN
#{classId}
ORDER BY att.attendance_date DESC

SELECT student_id as studentId,
       COUNT(*)   as lateCount
FROM student_attendance
WHERE deleted = 0

    AND student_id = #{studentId}


    AND FIND_IN_SET(#{status}, status)


    AND attendance_date >= #{startDate}


    AND attendance_date <= #{endDate}

SELECT student_id as studentId,
       COUNT(*)   as lateCount
FROM student_attendance
WHERE school_id = #{schoolId}
  AND deleted = 0
  AND FIND_IN_SET(1, status)

    AND class_id = #{classId}


    AND student_id IN

        #{studentId}


GROUP BY student_id

SELECT student_id AS studentId, COUNT(*) AS lateCount
FROM student_attendance
WHERE class_id = #{classId}

        AND attendance_date >= #{startDate}


        AND attendance_date <= #{endDate}

AND FIND_IN_SET(1, status)
  AND deleted = 0
GROUP BY student_id

SELECT *
FROM student_attendance
WHERE class_id = #{classId}

    AND attendance_date >= #{startDate}


    AND attendance_date <= #{endDate}

AND FIND_IN_SET(1, status)
AND deleted = 0
